const { Configuration, OpenAIApi } = require("openai");
const readline = require('readline-sync');

// Create configuration for OpenAI
const configuration = new Configuration({
  apiKey: "YOUR_OPENAI_API_KEY", // replace this with your own API key
});

// Create a new instance of the OpenAIApi using the above configuration
const openai = new OpenAIApi(configuration);

async function main() {
    const userInput = readline.question('Please describe how you would like to automate this process: ');
  
    // Send prompts to AI model
    const response = await openai.createCompletion({
      model: "text-davinci-003",
      prompt: `Write a Node.js script that will ${userInput}`,
      temperature: 0,
      max_tokens: 150,
    });
  
    // Execute generated code
    eval(response.data.choices[0].text);
}
main();